<template>
  <Breadcrumb />
  <!--카테고리-->
  <div class="category">
    <button v-for="(cate,index) in categorys" :key="index" :class="[{active : currentCate === index}]" @click="currentCate = index;"><router-link :to="cate.link">{{cate.title}} <sup></sup></router-link></button>
  </div>
  <!--포폴리스트-->
  <div class="work list">
    <div class="work-item" v-for="(portData,i) in filteredList" :key="i">
      <a :href="portData.link" :target="portData.target">
        <div class="thumb" :style="{backgroundImage: `url(${portData.img})`}"></div>
        <div class="title">
          <h4>{{portData.title}}</h4>
          <p>{{portData.desc}}</p>
        </div>
      </a>
    </div>
  </div>
  <!--푸터-->
  <div class="footer-wrap">
    <Sns />
    <Footer />
  </div>
</template>

<script>
export default {
  name: 'Work',
  inheritAttrs: false,//부모로부터 전달 받은 Attribute가 자식의 Attribute로 설정되지 않음
  props: {
    categorys : Array,
    postList : Array,
  },
  data() {
    return {
      currentCate : "",
    }
  },
  computed: {
    filteredList(){
      return this.postList.filter(portData => {
        if(this.$route.params.title == "all"){
          return portData
        } else {
          return portData.category == this.$route.params.title;
        }
      })
    },
  },
}
</script>

